insert into public.categories(name,slug,sort_order) values ('Learning Management System','learning-management-system',1),('Event Website','event-website',2) on conflict do nothing;
insert into public.technologies(name,slug) values ('React','react'),('Vite','vite'),('PHP','php'),('MySQL','mysql'),('REST API','rest-api'),('JWT Authentication','jwt-authentication'),('JavaScript','javascript'),('Responsive CSS','responsive-css') on conflict do nothing;
insert into public.projects(title,slug,short_description,full_description,live_url,project_status,is_featured,is_published,sort_order) values ('Spark Learning Management System','spark-lms','A modern learning management system for students, faculty, administrators, and training organizations.','## A flexible learning platform\n\nSpark LMS supports courseware, lessons, quizzes, surveys, announcements, reporting, collaboration, and support workflows.', 'https://spark.fitacademy.ph/','Completed',true,true,1),('Chantelle''s First Birthday Website','chantelles-first-birthday-website','A custom, guest-focused event website for a first birthday celebration.','## A memorable event experience\n\nA fast, mobile-friendly landing page that gives guests key celebration details in a warm, engaging format.','https://chantelle1stbirthday.online/','Completed',true,true,2) on conflict(slug) do nothing;
insert into public.project_categories(project_id,category_id) select p.id,c.id from public.projects p join public.categories c on (p.slug='spark-lms' and c.slug='learning-management-system') or (p.slug='chantelles-first-birthday-website' and c.slug='event-website') on conflict do nothing;
insert into public.project_technologies(project_id,technology_id) select p.id,t.id from public.projects p join public.technologies t on (p.slug='spark-lms' and t.slug in ('react','vite','php','mysql','rest-api','jwt-authentication')) or (p.slug='chantelles-first-birthday-website' and t.slug in ('react','vite','javascript','responsive-css')) on conflict do nothing;
